<?php
namespace App\Filament\Resources;
use App\Filament\Resources\PlanningResource\Pages; use App\Modules\Planning\Models\Enums\PlanningStatus; use App\Modules\Planning\Models\Planning; use App\Filament\Support\AdminUploads; use Filament\Forms; use Filament\Forms\Form; use Filament\Resources\Resource; use Filament\Tables; use Filament\Tables\Table;
class PlanningResource extends Resource { protected static ?string $model=Planning::class; protected static ?string $navigationIcon='heroicon-o-map-pin'; protected static ?string $navigationGroup='Nội dung'; protected static ?string $modelLabel='Quy hoạch'; protected static ?string $pluralModelLabel='Quy hoạch';
public static function form(Form $form): Form { return $form->schema([Forms\Components\TextInput::make('title')->label('Tiêu đề')->required(), Forms\Components\Select::make('status')->label('Trạng thái')->options(self::enumOptions(PlanningStatus::class))->required(), Forms\Components\TextInput::make('updated_year')->label('Năm cập nhật')->numeric(), Forms\Components\TextInput::make('city')->label('Tỉnh/Thành'), Forms\Components\TextInput::make('district')->label('Quận/Huyện'), Forms\Components\TextInput::make('sub_area')->label('Phân khu'), Forms\Components\TextInput::make('symbol')->label('Ký hiệu'), Forms\Components\TextInput::make('density')->label('Mật độ'), Forms\Components\TextInput::make('max_height')->label('Chiều cao tối đa'), Forms\Components\TextInput::make('land_use_ratio')->label('Hệ số sử dụng đất'), Forms\Components\TextInput::make('setback')->label('Khoảng lùi'), Forms\Components\TextInput::make('latitude')->label('Vĩ độ')->numeric(), Forms\Components\TextInput::make('longitude')->label('Kinh độ')->numeric(), AdminUploads::image('map_image', 'Ảnh bản đồ', 'admin/plannings')->columnSpanFull(), Forms\Components\TextInput::make('pdf_url')->label('File PDF')->columnSpanFull(), Forms\Components\Textarea::make('description')->label('Mô tả')->columnSpanFull(), Forms\Components\Textarea::make('land_type_notes')->label('Ghi chú loại đất')->columnSpanFull(), Forms\Components\RichEditor::make('content')->label('Nội dung chi tiết')->columnSpanFull()])->columns(2); }
public static function table(Table $table): Table { return $table->columns([Tables\Columns\TextColumn::make('title')->label('Quy hoạch')->searchable()->sortable(), Tables\Columns\TextColumn::make('city')->label('Tỉnh/Thành'), Tables\Columns\TextColumn::make('district')->label('Quận/Huyện'), Tables\Columns\TextColumn::make('status')->label('Trạng thái')->formatStateUsing(fn($state)=>$state instanceof PlanningStatus?$state->label():PlanningStatus::tryFrom((int)$state)?->label())->badge(), Tables\Columns\TextColumn::make('updated_year')->label('Năm')])->actions([Tables\Actions\EditAction::make(),Tables\Actions\DeleteAction::make()]); } public static function getPages(): array { return ['index'=>Pages\ListPlannings::route('/'),'create'=>Pages\CreatePlanning::route('/create'),'edit'=>Pages\EditPlanning::route('/{record}/edit')]; } private static function enumOptions(string $enum): array { return collect($enum::cases())->mapWithKeys(fn($case)=>[$case->value=>$case->label()])->all(); } }
